1	//! Graph GENERATION (BEHAVIOR.md §4, §6): mapping a proof-state / constraint-system
2	//! description onto the DOT [`Graph`] model, over an independent input model
3	//! designed from observed paired `main/proof` sequents and `interactive-graph-def`
4	//! graphs.
5	//!
6	//! What the observed system→graph mapping does, structurally (each point traces to
7	//! corpus/live observation — see BEHAVIOR.md §4, §6):
8	//!   * a **rule instance** `#t : Rule[actions]` becomes a `record` node with up to
9	//!     three groups `{premises}|{info}|{conclusions}`; the **info** group (the
10	//!     `#t : Rule[…]` cell) is always present (100 % of 160 409 corpus records),
11	//!     and an **empty** premise or conclusion group is dropped (so a source rule
12	//!     with no premises renders `{info}|{concl}`);
13	//!   * an intruder-knowledge fact renders as a gray `!KU( m ) @ #t` **ellipse**;
14	//!     a protocol action/event as a darkblue `Fact @ #t` ellipse; a compressed
15	//!     intruder rule as an uncolored `#t : rule` ellipse; a bare **timepoint**
16	//!     (`#i`, `#decrypt`, the designated `#last`) as an uncolored `#var` ellipse;
17	//!   * an unresolved node referenced by an open premise renders as an
18	//!     **invtrapezium** `(#var, idx)` (BEHAVIOR.md §3d);
19	//!   * a **role**-annotated record (role ≠ `Undefined`) is packed into a
20	//!     `subgraph "cluster_<Role>_Session_<k>"` block; role-annotated theories emit
21	//!     the compact header and free (non-role) nodes stay at the top level, in id
22	//!     order, *before* every cluster (BEHAVIOR.md §4);
23	//!   * **edges** connect a conclusion port to a premise port (structural), or an
24	//!     intruder deduction (red dashed), message (gray30), temporal order (blue3 /
25	//!     black dashed), etc. — the finite observed style vocabulary (§3c);
26	//!   * `n<K>` ids come from [`crate::alloc`]; record-cell text is wrapped/escaped
27	//!     by [`crate::render::wrap_cell`]; the header is inferred by role (§4).
28	//!
29	//! Two cell-content input paths, both flowing through the same wrap/escape
30	//! pipeline: [`RuleInstance`] carries [`Fact`]s (this crate renders + wraps them),
31	//! and [`RawRule`] carries PRE-RENDERED cell strings (the consumer's own printer
32	//! produced them; this crate still wraps and escapes). GAPS (need the GPL solver;
33	//! not derivable from output): *which* nodes/edges/clusters a raw constraint system
34	//! yields, the per-rule/per-cluster color hash, and the accumulated-column wrap
35	//! trigger for cells deep on a record line (BEHAVIOR.md §3f).
36	
37	use crate::alloc::NodeIdAllocator;
38	use crate::model::*;
39	use crate::render::{render_info, wrap_cell, Fact};
40	
41	/// A per-record cluster assignment (BEHAVIOR.md §4). `label` is the cluster label
42	/// WITHOUT the `cluster_` prefix (e.g. `Initiator_Session_1`, observed always
43	/// `<Role>_Session_<k>`); `color` is the 8-hex ARGB used for the block's
44	/// `color`/`fillcolor`. Both are solver-supplied (a content GAP).
45	#[derive(Clone, Debug)]
46	pub struct ClusterRef {
47	    pub label: String,
48	    pub color: String,
49	}
50	
51	impl ClusterRef {
52	    pub fn new(label: &str, color: &str) -> Self {
53	        ClusterRef { label: label.into(), color: color.into() }
54	    }
55	}
56	
57	/// A rule instance: one record node with premise / info / conclusion cells, built
58	/// from [`Fact`]s (the crate renders and wraps them).
59	#[derive(Clone, Debug)]
60	pub struct RuleInstance {
61	    pub temporal: String,
62	    pub rule: String,
63	    pub role: String,
64	    pub premises: Vec<Fact>,
65	    pub actions: Vec<Fact>,
66	    pub conclusions: Vec<Fact>,
67	    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
68	    pub fillcolor: String,
69	    /// `black` on the light MSR palette, `white`/`black` on the role palette.
70	    pub fontcolor: String,
71	    /// If set, this record is packed into a `cluster_<label>` subgraph (§4).
72	    pub cluster: Option<ClusterRef>,
73	}
74	
75	impl RuleInstance {
76	    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
77	        RuleInstance {
78	            temporal: temporal.into(),
79	            rule: rule.into(),
80	            role: Role::UNDEFINED.into(),
81	            premises: Vec::new(),
82	            actions: Vec::new(),
83	            conclusions: Vec::new(),
84	            fillcolor: fillcolor.into(),
85	            fontcolor: "black".into(),
86	            cluster: None,
87	        }
88	    }
89	    pub fn premises(mut self, f: Vec<Fact>) -> Self {
90	        self.premises = f;
91	        self
92	    }
93	    pub fn actions(mut self, f: Vec<Fact>) -> Self {
94	        self.actions = f;
95	        self
96	    }
97	    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
98	        self.conclusions = f;
99	        self
100	    }
101	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
102	        self.role = r.into();
103	        self.fontcolor = fontcolor.into();
104	        self
105	    }
106	    /// Pack this record into the `cluster_<label>` subgraph (BEHAVIOR.md §4).
107	    pub fn cluster(mut self, label: &str, color: &str) -> Self {
108	        self.cluster = Some(ClusterRef::new(label, color));
109	        self
110	    }
111	    /// The flat, un-escaped cell strings (premises, info, conclusions), for the
112	    /// shared record builder.
113	    fn spec(&self) -> RecordSpec {
114	        RecordSpec {
115	            premises: self.premises.iter().map(Fact::render_flat).collect(),
116	            info: render_info(&self.temporal, &self.rule, &self.actions),
117	            conclusions: self.conclusions.iter().map(Fact::render_flat).collect(),
118	            fillcolor: self.fillcolor.clone(),
119	            fontcolor: self.fontcolor.clone(),
120	            role: self.role.clone(),
121	            cluster: self.cluster.clone(),
122	        }
123	    }
124	}
125	
126	/// A rule instance whose cells are supplied as **pre-rendered flat strings**
127	/// (BEHAVIOR.md interop, round 5). The consumer renders fact/term text with its own
128	/// printer — including any abbreviation — and this crate's wrap + escape pipeline
129	/// ([`wrap_cell`]) applies to those strings exactly as it does to a [`RuleInstance`]'s
130	/// rendered facts. `info` is the whole info-cell text (`#t : Rule[…]`); `premises`
131	/// and `conclusions` are one flat fact string per cell.
132	#[derive(Clone, Debug, Default)]
133	pub struct RawRule {
134	    pub premises: Vec<String>,
135	    pub info: String,
136	    pub conclusions: Vec<String>,
137	    pub fillcolor: String,
138	    pub fontcolor: String,
139	    pub role: String,
140	    pub cluster: Option<ClusterRef>,
141	}
142	
143	impl RawRule {
144	    /// A raw record with the given info-cell text and per-rule fill color; role
145	    /// defaults to `Undefined`, fontcolor to `black`.
146	    pub fn new(info: &str, fillcolor: &str) -> Self {
147	        RawRule {
148	            premises: Vec::new(),
149	            info: info.into(),
150	            conclusions: Vec::new(),
151	            fillcolor: fillcolor.into(),
152	            fontcolor: "black".into(),
153	            role: Role::UNDEFINED.into(),
154	            cluster: None,
155	        }
156	    }
157	    pub fn premises(mut self, cells: Vec<String>) -> Self {
158	        self.premises = cells;
159	        self
160	    }
161	    pub fn conclusions(mut self, cells: Vec<String>) -> Self {
162	        self.conclusions = cells;
163	        self
164	    }
165	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
166	        self.role = r.into();
167	        self.fontcolor = fontcolor.into();
168	        self
169	    }
170	    pub fn cluster(mut self, label: &str, color: &str) -> Self {
171	        self.cluster = Some(ClusterRef::new(label, color));
172	        self
173	    }
174	    fn spec(&self) -> RecordSpec {
175	        RecordSpec {
176	            premises: self.premises.clone(),
177	            info: self.info.clone(),
178	            conclusions: self.conclusions.clone(),
179	            fillcolor: self.fillcolor.clone(),
180	            fontcolor: self.fontcolor.clone(),
181	            role: self.role.clone(),
182	            cluster: self.cluster.clone(),
183	        }
184	    }
185	}
186	
187	/// The flat (un-escaped, un-wrapped) content of a record, shared by the Term-based
188	/// [`RuleInstance`] and the pre-rendered [`RawRule`]. Cell text is wrapped and
189	/// escaped by [`build_record`].
190	struct RecordSpec {
191	    premises: Vec<String>,
192	    info: String,
193	    conclusions: Vec<String>,
194	    fillcolor: String,
195	    fontcolor: String,
196	    role: String,
197	    cluster: Option<ClusterRef>,
198	}
199	
200	impl RecordSpec {
201	    fn cell_count(&self) -> usize {
202	        self.premises.len() + 1 /* info */ + self.conclusions.len()
203	    }
204	}
205	
206	/// One node of the input system, in emission order.
207	#[derive(Clone, Debug)]
208	pub enum GraphNode {
209	    /// A rule instance built from [`Fact`]s (rendered + wrapped by this crate).
210	    Rule(RuleInstance),
211	    /// A rule instance whose cells are pre-rendered strings (still wrapped/escaped).
212	    RawRule(RawRule),
213	    /// `!KU( term ) @ #t` — intruder knowledge (drawn as a gray ellipse). `term`
214	    /// is the pre-rendered message text.
215	    Knowledge { term: String, temporal: String },
216	    /// `Fact @ #t` — a protocol action/event (darkblue ellipse). `fact` is
217	    /// pre-rendered.
218	    Action { fact: String, temporal: String },
219	    /// `#t : rule` — a compressed rule shown as a single uncolored ellipse.
220	    Compressed { temporal: String, rule: String },
221	    /// `#var` — a bare timepoint ellipse (uncolored). Observed for ordinary
222	    /// timepoint variables (`#i`, `#decrypt`, `#t1`, …) and, when a constraint
223	    /// system carries a designated last timepoint (induction), the `#last` node
224	    /// (`#last` is the target of `color="black",style="dashed"` before-edges).
225	    Temporal { var: String },
226	    /// `(#var, idx)` — an unresolved node referenced by an open premise
227	    /// (invtrapezium), the target of a conclusion→absent-node structural edge.
228	    OpenTarget { node_var: String, premise_index: usize },
229	    /// A node with an explicit `shape` and label — the extension point for shapes
230	    /// beyond the observed set (e.g. the `trapezium` dual, an unresolved source
231	    /// feeding a present premise, which is spec-named but was **not observed** in
232	    /// the corpus or any probe; see BEHAVIOR.md §3d).
233	    Shaped { label: String, shape: String, color: Option<String> },
234	}
235	
236	impl GraphNode {
237	    /// The designated last timepoint `#last` (BEHAVIOR.md §3d/§6).
238	    pub fn last() -> Self {
239	        GraphNode::Temporal { var: "last".into() }
240	    }
241	    /// A record node from a [`RecordSpec`], if this node is one.
242	    fn record_spec(&self) -> Option<RecordSpec> {
243	        match self {
244	            GraphNode::Rule(r) => Some(r.spec()),
245	            GraphNode::RawRule(r) => Some(r.spec()),
246	            _ => None,
247	        }
248	    }
249	}
250	
251	/// An endpoint reference into the input system (resolved to `n<K>[:n<port>]`).
252	#[derive(Clone, Copy, Debug)]
253	pub enum EndRef {
254	    /// The whole node (no port) — ellipses, invtrapezium, legend.
255	    Whole(usize),
256	    /// Conclusion `c` of rule node `n` (→ its conclusion port).
257	    Conclusion(usize, usize),
258	    /// Premise `p` of rule node `n` (→ its premise port).
259	    Premise(usize, usize),
260	}
261	
262	/// The finite observed edge-style vocabulary (BEHAVIOR.md §3c). Each maps to a
263	/// fixed attribute list emitted verbatim.
264	#[derive(Clone, Copy, Debug)]
265	pub enum EdgeStyle {
266	    /// `style="bold",weight="10.0",color="gray50"` — structural, into a target.
267	    StructuralGray,
268	    /// `style="bold",weight="10.0"` — structural (uncolored).
269	    Structural,
270	    /// `color="gray30"` — message / standard edge.
271	    Message,
272	    /// `color="red",style="dashed"` — intruder `!KU` deduction.
273	    KnowledgeDeduction,
274	    /// `color="orangered2"` — deduction variant.
275	    Deduction,
276	    /// `color="blue3",style="dashed"` — temporal-order edge.
277	    TemporalBlue,
278	    /// `color="black",style="dashed"` — before / less-than temporal edge (e.g. into
279	    /// the `#last` node).
280	    TemporalBlack,
281	    /// `style="invis"` — ranking edge to the legend.
282	    Invis,
283	}
284	
285	impl EdgeStyle {
286	    /// The exact attribute pairs, in observed key order.
287	    pub fn attrs(self) -> Vec<(String, String)> {
288	        let raw: &[(&str, &str)] = match self {
289	            EdgeStyle::StructuralGray => {
290	                &[("style", "bold"), ("weight", "10.0"), ("color", "gray50")]
291	            }
292	            EdgeStyle::Structural => &[("style", "bold"), ("weight", "10.0")],
293	            EdgeStyle::Message => &[("color", "gray30")],
294	            EdgeStyle::KnowledgeDeduction => &[("color", "red"), ("style", "dashed")],
295	            EdgeStyle::Deduction => &[("color", "orangered2")],
296	            EdgeStyle::TemporalBlue => &[("color", "blue3"), ("style", "dashed")],
297	            EdgeStyle::TemporalBlack => &[("color", "black"), ("style", "dashed")],
298	            EdgeStyle::Invis => &[("style", "invis")],
299	        };
300	        raw.iter().map(|(k, v)| (k.to_string(), v.to_string())).collect()
301	    }
302	}
303	
304	/// An edge in the input system.
305	#[derive(Clone, Debug)]
306	pub struct SysEdge {
307	    pub src: EndRef,
308	    pub dst: EndRef,
309	    pub style: EdgeStyle,
310	}
311	
312	impl SysEdge {
313	    pub fn new(src: EndRef, dst: EndRef, style: EdgeStyle) -> Self {
314	        SysEdge { src, dst, style }
315	    }
316	}
317	
318	/// A proof-state graph description: nodes in emission order, edges, and an
319	/// optional pre-rendered legend (inner HTML of the `plain` node) plus the invis
320	/// edges wiring it in.
321	#[derive(Clone, Debug, Default)]
322	pub struct System {
323	    pub nodes: Vec<GraphNode>,
324	    pub edges: Vec<SysEdge>,
325	    /// Legend inner HTML (from [`crate::abbrev::Abbreviator::legend_html`]); if
326	    /// non-empty a `{ rank="sink"; … }` block is appended.
327	    pub legend_html: Option<String>,
328	    /// Invis edges to the legend node (emitted after the sink block).
329	    pub legend_edges: Vec<(EndRef, ())>,
330	}
331	
332	/// Resolved ids for one system node.
333	enum Resolved {
334	    // The info port is never an edge endpoint, so it is not retained here.
335	    Record { ports_prem: Vec<String>, ports_concl: Vec<String>, node: String },
336	    Node(String),
337	}
338	
339	impl Resolved {
340	    fn node_id(&self) -> &str {
341	        match self {
342	            Resolved::Record { node, .. } => node,
343	            Resolved::Node(id) => id,
344	        }
345	    }
346	}
347	
348	/// Build the DOT [`Graph`] for a [`System`]: allocate ids in emission order (so id
349	/// order == file order), emit free (non-clustered) node statements at the top
350	/// level, then the `cluster_…` subgraph blocks (role records, grouped by cluster
351	/// label in first-appearance order), then edges, then the legend sink-block + its
352	/// invis edges. Header is inferred from roles (§4).
353	pub fn generate(sys: &System) -> Graph {
354	    let mut alloc = NodeIdAllocator::new();
355	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
356	
357	    // Free top-level node statements, in emission order.
358	    let mut free: Vec<Stmt> = Vec::new();
359	    // Clusters: label -> (color, record statements), with first-appearance order.
360	    let mut cluster_order: Vec<String> = Vec::new();
361	    let mut clusters: std::collections::HashMap<String, (String, Vec<Stmt>)> =
362	        std::collections::HashMap::new();
363	
364	    // Pass 1: allocate ids and build node statements in emission order. A clustered
365	    // record's statement is routed into its cluster bucket; everything else is free.
366	    for node in &sys.nodes {
367	        if let Some(spec) = node.record_spec() {
368	            let ids = alloc.record(spec.cell_count());
369	            let mut it = ids.ports.into_iter();
370	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
371	            let port_info = it.next().unwrap();
372	            let ports_concl: Vec<String> =
373	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
374	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
375	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
376	            match &spec.cluster {
377	                Some(c) => {
378	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
379	                        cluster_order.push(c.label.clone());
380	                        (c.color.clone(), Vec::new())
381	                    });
382	                    entry.1.push(stmt);
383	                }
384	                None => free.push(stmt),
385	            }
386	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
387	            continue;
388	        }
389	        let id = alloc.node();
390	        let stmt = match node {
391	            GraphNode::Knowledge { term, temporal } => {
392	                let label = format!("!KU( {} ) @ #{}", term, temporal);
393	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
394	            }
395	            GraphNode::Action { fact, temporal } => {
396	                let label = format!("{} @ #{}", fact, temporal);
397	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
398	            }
399	            GraphNode::Compressed { temporal, rule } => {
400	                let label = format!("#{} : {}", temporal, rule);
401	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
402	            }
403	            GraphNode::Temporal { var } => {
404	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
405	            }
406	            GraphNode::OpenTarget { node_var, premise_index } => {
407	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
408	            }
409	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
410	                id.clone(),
411	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
412	            )),
413	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
414	        };
415	        free.push(stmt);
416	        resolved.push(Resolved::Node(id));
417	    }
418	
419	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
420	    let mut g = Graph::new(Header::Simple);
421	    for s in free {
422	        g.push(s);
423	    }
424	    for label in &cluster_order {
425	        let (color, body) = clusters.remove(label).unwrap();
426	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
427	    }
428	
429	    // Pass 2: edges.
430	    for e in &sys.edges {
431	        let src = endpoint(&resolved, e.src);
432	        let dst = endpoint(&resolved, e.dst);
433	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
434	    }
435	
436	    // Pass 3: legend sink-block, then its invis edges (observed order).
437	    if let Some(html) = &sys.legend_html {
438	        if !html.is_empty() {
439	            let legend_id = alloc.node();
440	            let block = RankBlock {
441	                rank: "sink".into(),
442	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
443	            };
444	            g.push(Stmt::RankBlock(block));
445	            for (from, ()) in &sys.legend_edges {
446	                let src = endpoint(&resolved, *from);
447	                g.push(Stmt::Edge(Edge {
448	                    src,
449	                    dst: EndPoint::node(legend_id.clone()),
450	                    attrs: EdgeStyle::Invis.attrs(),
451	                }));
452	            }
453	        }
454	    }
455	
456	    g.set_inferred_header();
457	    g
458	}
459	
460	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
461	/// Empty premise / conclusion groups are dropped; the info group is always kept
462	/// (matches the observed group structure). Each cell's flat text is wrapped and
463	/// escaped by [`wrap_cell`].
464	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
465	    let mut columns: Vec<Vec<Cell>> = Vec::new();
466	    if !spec.premises.is_empty() {
467	        columns.push(cells(&spec.premises, ports_prem));
468	    }
469	    columns.push(vec![Cell::new(port_info, wrap_cell(&spec.info))]);
470	    if !spec.conclusions.is_empty() {
471	        columns.push(cells(&spec.conclusions, ports_concl));
472	    }
473	    Record {
474	        columns,
475	        fillcolor: spec.fillcolor.clone(),
476	        fontcolor: spec.fontcolor.clone(),
477	        role: Role(spec.role.clone()),
478	    }
479	}
480	
481	fn cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
482	    flat_cells
483	        .iter()
484	        .zip(ports)
485	        .map(|(text, p)| Cell::new(p.clone(), wrap_cell(text)))
486	        .collect()
487	}
488	
489	/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
490	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
491	    match r {
492	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
493	        EndRef::Conclusion(n, c) => {
494	            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
495	                EndPoint::port(node.clone(), ports_concl[c].clone())
496	            } else {
497	                EndPoint::node(resolved[n].node_id().to_string())
498	            }
499	        }
500	        EndRef::Premise(n, p) => {
501	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
502	                EndPoint::port(node.clone(), ports_prem[p].clone())
503	            } else {
504	                EndPoint::node(resolved[n].node_id().to_string())
505	            }
506	        }
507	    }
508	}
