9	//! Graph representation, simplification, abbreviations.
10	//!
11	//! Mirrors the layout of `lib/theory/src/Theory/Constraint/System/Graph/`:
12	//!
13	//! - [`repr`]         -> `GraphRepr.hs`
14	//! - [`simplify`]     -> `Simplification.hs`
15	//! - [`abbreviation`] -> `Abbreviation.hs`
16	//! - [`options`]      -> the top-level `Graph.hs` `GraphOptions` record.
17	
18	pub mod abbreviation;
19	pub mod options;
20	pub mod render_system;
21	pub mod repr;
22	pub mod simplify;
23	
24	pub use render_system::RenderSystem;
25	
26	pub use options::{GraphOptions, graph_options_from_query, graph_options_from_params};
27	pub use repr::{
