23	/// Options for graph generation.  Mirror of `GraphOptions`.
24	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
25	pub struct GraphOptions {
26	    pub simplification_level: SimplificationLevel,
27	    pub show_auto_source: bool,
28	    /// If `true`, cluster by similar rule names; if `false`, cluster
29	    /// by role.  Matches Haskell `goClustering`.
