48	/// Build `GraphOptions` from a render-request query string.
49	///
50	/// Faithful port of Haskell `getOptions` (`Web/Handler.hs`).
51	/// The flags are presence-based (`un*`/`no-*` toggles arrive with an empty
52	/// value, so presence, not value, is what matters):
53	/// - `uncompress`     present => `compress = false`        (HS `isNothing`)
54	/// - `unabbreviate`   present => `abbreviate = false`      (HS `isNothing`)
55	/// - `no-auto-sources` present => `show_auto_source = false` (HS `isNothing`;
56	///   absent => `true`, which overrides the struct default of `false`)
57	/// - `clustering`     present => `clustering_similar_names = true` (HS `isJust`)
58	/// - `simplification` value read with `SimplificationLevel`'s derived `Read`,
59	///   i.e. only the tokens `SL0..SL3` parse (numeric `0..3`, the value the UI
60	///   actually sends, fails to parse); anything else falls back to `SL2`
61	///   (HS `fromMaybe SL2 (simpl >>= readMaybe . T.unpack)`).
62	///
63	/// The `uncompact`/`CompactBoringNodes` flag belongs to `DotOptions`
64	/// (`Handler.hs`), not `GraphOptions`, so it is not handled here.
65	///
66	/// Convenience wrapper that parses the query string and delegates to
67	/// [`graph_options_from_params`]; live handlers go through
68	/// `graph_options_from_params` directly, so this entry point is used
69	/// only where a raw query string is on hand (and in tests).
70	pub fn graph_options_from_query(qs: &str) -> GraphOptions {
71	    let params: HashMap<String, String> = qs.split('&')
72	        .filter(|kv| !kv.is_empty())
73	        .map(|kv| {
74	            let mut it = kv.splitn(2, '=');
75	            let k = it.next().unwrap_or("");
76	            let v = it.next().unwrap_or("");
77	            (k.to_string(), v.to_string())
78	        }).collect();
79	    graph_options_from_params(&params)
80	}
81	
82	/// Build `GraphOptions` from an already-parsed query parameter map.
83	/// Shares the keyed-lookup logic of [`graph_options_from_query`] so callers
84	/// that already hold a `HashMap` need not re-serialise it to a query string.
85	pub fn graph_options_from_params(params: &HashMap<String, String>) -> GraphOptions {
86	    let simplification_level = params
87	        .get("simplification")
88	        .and_then(|v| read_simplification_level(v))
89	        .unwrap_or(SimplificationLevel::SL2);
90	
91	    GraphOptions {
92	        simplification_level,
93	        // `isNothing <$> lookupGetParam "no-auto-sources"`: absent => true.
94	        show_auto_source: !params.contains_key("no-auto-sources"),
95	        // `_goClustering = isJust clustering`.
96	        clustering_similar_names: params.contains_key("clustering"),
97	        // `isNothing <$> lookupGetParam "unabbreviate"`.
98	        abbreviate: !params.contains_key("unabbreviate"),
99	        // `isNothing <$> lookupGetParam "uncompress"`.
100	        compress: !params.contains_key("uncompress"),
101	    }
102	}
103	
104	/// Parse a `SimplificationLevel` exactly as Haskell's derived `Read` would.
105	///
106	/// The data type is `data SimplificationLevel = SL0 | SL1 | SL2 | SL3`
107	/// (`Graph.hs`), so its derived `Read` parses only the bare
108	/// constructor tokens. Following `Read`'s lexer it skips leading/trailing
109	/// whitespace and accepts one or more matched pairs of surrounding parentheses;
110	/// numeric input (e.g. `"2"`) fails. Returns `None` on any non-match.
111	fn read_simplification_level(s: &str) -> Option<SimplificationLevel> {
112	    let mut t = s.trim();
113	    // Derived `Read` allows one (or more) matched pairs of surrounding parens.
114	    while let (Some(inner), true) = (t.strip_prefix('('), t.ends_with(')')) {
115	        t = inner.strip_suffix(')')?.trim();
116	    }
117	    match t {
118	        "SL0" => Some(SimplificationLevel::SL0),
119	        "SL1" => Some(SimplificationLevel::SL1),
120	        "SL2" => Some(SimplificationLevel::SL2),
121	        "SL3" => Some(SimplificationLevel::SL3),
122	        _ => None,
123	    }
124	}
