117	/// `extractBaseName name` returns `Just base` when `name = base_<digits>`.
118	/// Mirror of `extractBaseName` (GraphRepr.hs:217-225).
119	pub fn extract_base_name(name: &str) -> Option<String> {
120	    let parts: Vec<&str> = name.split('_').collect();
121	    if parts.len() < 2 { return None; }
122	    let last = parts.last().unwrap();
123	    if !last.is_empty() && last.chars().all(|c| c.is_ascii_digit()) {
124	        Some(parts[..parts.len() - 1].join("_"))
125	    } else {
126	        None
127	    }
128	}
