130	/// Return the rule's case-name (e.g. `Setup_1`) for proto-rules, else None.
131	/// Mirror of `getRuleNameByNode` (GraphRepr.hs:208-214) which renders
132	/// `showRuleCaseName` -> `prettyProtoRuleName` (Rule.hs:1164-1167):
133	/// `StandRule n -> prefixIfReserved n`, `FreshRule -> "Fresh"`.
134	/// `prefixIfReserved` (Rule.hs:1154-1162) prepends `_` when the name is a
135	/// reserved rule name or already starts with `_`.  This is plain
136	/// `showRuleCaseName`, NOT the SAPiC-trimming `showDotRuleCaseName`.
137	pub fn rule_name_by_node(n: &GNode) -> Option<String> {
138	    if let NodeType::System(ru) = &n.ty {
139	        if let RuleInfo::Proto(p) = &ru.info {
140	            return Some(match &p.name {
141	                ProtoRuleName::Stand(s) => {
142	                    let reserved = tamarin_theory::rule::reserved_rule_names();
143	                    if reserved.contains(s) || s.starts_with('_') {
144	                        format!("_{s}")
145	                    } else {
146	                        s.to_string()
147	                    }
148	                }
149	                ProtoRuleName::Fresh => "Fresh".to_string(),
150	            });
151	        }
152	    }
153	    None
154	}
