156	/// Mirror of `groupBySimilarName` — group nodes by their rule's base name.
157	pub fn group_by_similar_name<'a>(
158	    nodes: &'a [GNode],
159	) -> BTreeMap<String, Vec<&'a GNode>> {
160	    let mut out: BTreeMap<String, Vec<&'a GNode>> = BTreeMap::new();
161	    for n in nodes {
162	        if let Some(rn) = rule_name_by_node(n) {
163	            if let Some(base) = extract_base_name(&rn) {
164	                out.entry(base).or_default().push(n);
165	            }
166	        }
167	    }
168	    out
169	}
