171	/// Filter edges keeping only those whose endpoints are both in `node_ids`.
172	/// Mirror of `filterEdgesForCluster`.
173	pub fn filter_edges_for_cluster(
174	    node_ids: &BTreeSet<NodeId>,
175	    edges: &[GEdge],
176	) -> Vec<GEdge> {
177	    edges.iter().filter(|e| match e {
178	        GEdge::System(s, t) | GEdge::UnsolvedChain(s, t) =>
179	            node_ids.contains(&s.0) && node_ids.contains(&t.0),
180	        GEdge::Less(la) =>
181	            node_ids.contains(&la.smaller) && node_ids.contains(&la.larger),
182	    }).cloned().collect()
183	}
