185	/// Group `nodes` into weakly-connected components under the projection
186	/// from `edges`.  Mirror of `findConnectedComponents`.
187	pub fn find_connected_components<'a>(
188	    nodes: &'a [&'a GNode],
189	    edges: &[GEdge],
190	) -> Vec<Vec<&'a GNode>> {
191	    // Build undirected adjacency.  Mirror of `expandCluster`, which walks
192	    // ONLY `SystemEdge`s for connectivity — `LessEdge`/`UnsolvedChain`
193	    // edges are not matched and so never join two nodes into one component.
194	    let mut adj: BTreeMap<NodeId, BTreeSet<NodeId>> = BTreeMap::new();
195	    for e in edges {
196	        if let GEdge::System(s, t) = e {
197	            let (a, b) = (s.0.clone(), t.0.clone());
198	            adj.entry(a.clone()).or_default().insert(b.clone());
199	            adj.entry(b).or_default().insert(a);
200	        }
201	    }
202	    let mut visited: BTreeSet<NodeId> = BTreeSet::new();
203	    let mut components: Vec<Vec<&'a GNode>> = Vec::new();
204	    let by_id: BTreeSet<NodeId> =
205	        nodes.iter().map(|n| n.id.clone()).collect();
206	    for n in nodes {
207	        if visited.contains(&n.id) { continue; }
208	        let mut stack = vec![n.id.clone()];
209	        let mut comp_set: BTreeSet<NodeId> = BTreeSet::new();
210	        while let Some(cur) = stack.pop() {
211	            if !visited.insert(cur.clone()) { continue; }
212	            comp_set.insert(cur.clone());
213	            if let Some(neighbors) = adj.get(&cur) {
214	                for nb in neighbors {
215	                    if !visited.contains(nb) && by_id.contains(nb) {
216	                        stack.push(nb.clone());
217	                    }
218	                }
219	            }
220	        }
221	        // HS `component = filter (\node -> get nNodeId node `elem` componentIds)
222	        // (n:ns)` (GraphRepr.hs:190): component nodes are kept in the ORIGINAL
223	        // `nodes` order, not DFS discovery order.  Filtering the full `nodes`
224	        // slice is safe because each node belongs to exactly one component
225	        // (globally `visited`), so the per-component relative order matches HS.
226	        let comp: Vec<&'a GNode> = nodes.iter().copied()
227	            .filter(|n| comp_set.contains(&n.id))
228	            .collect();
229	        if !comp.is_empty() { components.push(comp); }
230	    }
231	    // Haskell `go (n:ns) components = go remainingNodes (component : components)`
232	    // PREPENDS each newly-discovered component, so the returned list is in
233	    // reverse-discovery order.  We discover in the same node order but append,
234	    // so reverse here to match before downstream `zipWith [1..]` numbering.
235	    components.reverse();
236	    components
237	}
