239	/// Generic `addCluster` from `GraphRepr.hs:117-130`.  Given a grouping
240	/// of nodes (one group per cluster), it:
241	///   1. computes connected components within each group,
242	///   2. emits one cluster per component named `<group><suffix><N>`,
243	///   3. removes those nodes and the intra-cluster edges from the
244	///      top-level `GraphRepr` fields,
245	///   4. leaves cross-cluster + non-clustered nodes/edges in place.
246	pub fn add_cluster(
247	    repr: &mut GraphRepr,
248	    nodes_by_group: BTreeMap<String, Vec<&GNode>>,
249	    name_suffix: &str,
250	) {
251	    let all_edges = repr.edges.clone();
252	    let mut sub_clusters: Vec<Cluster> = Vec::new();
253	    for (group_name, group_nodes) in &nodes_by_group {
254	        let group_node_ids: BTreeSet<NodeId> =
255	            group_nodes.iter().map(|n| n.id.clone()).collect();
256	        let edges_for_group = filter_edges_for_cluster(&group_node_ids, &all_edges);
257	        let components = find_connected_components(group_nodes, &edges_for_group);
258	        for (i, comp) in components.into_iter().enumerate() {
259	            let comp_ids: BTreeSet<NodeId> =
260	                comp.iter().map(|n| n.id.clone()).collect();
261	            let edges_in_comp = filter_edges_for_cluster(&comp_ids, &all_edges);
262	            sub_clusters.push(Cluster {
263	                name: format!("{}{}{}", group_name, name_suffix, i + 1),
264	                nodes: comp.into_iter().cloned().collect(),
265	                edges: edges_in_comp,
266	            });
267	        }
268	    }
269	    // Collect all the edges and nodes absorbed by sub_clusters.
270	    // The cloned cluster edges live at different addresses than the
271	    // elements of `all_edges`, so absorbed edges must be filtered by
272	    // structural equality (not pointer identity).
273	    //
274	    // Nodes too must be removed by STRUCTURAL equality, mirroring HS
275	    // `remainingNodes = filter (`notElem` clusteredNodes) grNodes`
276	    // (GraphRepr.hs:127): a node id can appear TWICE in `grNodes` with
277	    // different types — e.g. the last-atom id is pushed both as a
278	    // `SystemNode` and as a free `LastAction` ellipse (see
279	    // `compute_basic_graph_repr`).  When the SystemNode is clustered,
280	    // an id-keyed filter would silently drop the free ellipse as well;
281	    // HS keeps it at top level (it is not an element of the cluster).
282	    let absorbed_nodes: Vec<GNode> = sub_clusters.iter()
283	        .flat_map(|c| c.nodes.iter().cloned())
284	        .collect();
285	    let absorbed_edges_struct: Vec<GEdge> = sub_clusters.iter()
286	        .flat_map(|c| c.edges.iter().cloned())
287	        .collect();
288	    let remaining_edges: Vec<GEdge> = all_edges.into_iter()
289	        .filter(|e| !absorbed_edges_struct.iter().any(|ae| ae == e))
290	        .collect();
291	    let remaining_nodes: Vec<GNode> = repr.nodes.iter()
292	        .filter(|n| !absorbed_nodes.iter().any(|an| an == *n))
293	        .cloned()
294	        .collect();
295	    repr.clusters = sub_clusters;
296	    repr.edges = remaining_edges;
297	    repr.nodes = remaining_nodes;
298	}
