303	    // and doesn't alias `repr`'s nodes field.
304	    let nodes_owned: Vec<GNode> = repr.nodes.clone();
305	    let groups: BTreeMap<String, Vec<&GNode>> = group_nodes_by_role(&nodes_owned);
