320	use tamarin_theory::constraint::constraints::Goal;
321	use tamarin_theory::constraint::system::System;
322	
323	/// Port of `computeBasicGraphRepr` from `Graph.hs:140-150`.
324	/// Collects from a `System`:
325	///   - rule nodes,
326	///   - unsolved-action atoms (KU goals etc.),
327	///   - the optional last-atom node,
328	///   - missing nodes referenced by edges.
329	pub fn compute_basic_graph_repr(sys: &System) -> GraphRepr {
330	    let mut nodes: Vec<GNode> = Vec::new();
331	    // 1. System rule instances.
332	    for (nid, ru) in sys.nodes.iter() {
333	        nodes.push(GNode { id: nid.clone(), ty: NodeType::System(ru.clone()) });
334	    }
335	    // 2. Unsolved action atoms — collect by node id.
336	    // HS `systemUnsolvedActionNodes se = map unsolvedActionNode
337	    // (collectBy $ unsolvedActionAtoms se)` (Graph.hs:105-108) does NOT filter
338	    // these ids against `sNodes`: if an id is both a system node and an
339	    // unsolved ActionG goal, HS emits BOTH a SystemNode and an
340	    // UnsolvedActionNode.  So there is no skip-if-already-a-system-node guard.
341	    let mut by_node: BTreeMap<NodeId, Vec<LNFact>> = BTreeMap::new();
342	    for (g, st) in sys.goals.iter() {
343	        if st.solved { continue; }
344	        if let Goal::Action(nid, fa) = g {
345	            by_node.entry(nid.clone()).or_default().push(fa.clone());
346	        }
347	    }
348	    for (nid, facts) in by_node {
349	        nodes.push(GNode {
350	            id: nid.clone(),
351	            ty: NodeType::UnsolvedAction(facts),
352	        });
353	    }
354	    // 3. Last-atom node.
355	    // HS `systemLastActionNode se = maybe [] (\nid -> [Node nid LastActionAtom])
356	    // (get Sys.sLastAtom se)` (Graph.hs:111-112) appends this UNCONDITIONALLY
357	    // whenever `sLastAtom` is set — it does NOT skip when the id coincides with
358	    // a system/unsolved node.  `cacheState` (Dot.hs:108) re-runs each node's
359	    // `dot` action and overwrites `dsNodes[v]`, so both the SystemNode record
360	    // AND the bare `#i` last-atom ellipse are emitted at the same id (the
361	    // ellipse ends up as `dsNodes[v]`, which drives less-edge resolution).  The
362	    // colliding dot-id is disambiguated in `dot.rs`.
363	    if let Some(la) = &sys.last_atom {
364	        nodes.push(GNode { id: la.clone(), ty: NodeType::LastAction });
365	    }
366	    // 4. Missing nodes referenced by edges.
367	    // HS `systemMissingNodes se = mapMaybe missingNode (S.toList sEdges)`
368	    // (Graph.hs:116-122): each edge yields AT MOST ONE missing node — `missingNode`
369	    // checks the source first (`MissingNode (Left idx)`), and only if the source
370	    // is present does it check the target (`MissingNode (Right idx)`).  The
371	    // membership test is `nid `notElem` nodelist` where `nodelist = map fst
372	    // (M.toList sNodes)` — i.e. against `sNodes` ONLY, never against
373	    // unsolved-action / last-atom ids.  There is also NO dedup among missing
374	    // nodes: two edges sharing the same missing endpoint emit it twice.
375	    // `systemMissingNodes` never inspects `sLessAtoms`; less-atoms contribute
376	    // edges (below), not nodes.
377	    let sys_node_ids: BTreeSet<NodeId> =
378	        sys.nodes.iter().map(|(id, _)| id.clone()).collect();
379	    for e in &sys.edges {
380	        if !sys_node_ids.contains(&e.src.0) {
381	            nodes.push(GNode {
382	                id: e.src.0.clone(),
383	                ty: NodeType::Missing(MissingHint::Conc(e.src.1)),
384	            });
385	        } else if !sys_node_ids.contains(&e.tgt.0) {
386	            nodes.push(GNode {
387	                id: e.tgt.0.clone(),
388	                ty: NodeType::Missing(MissingHint::Prem(e.tgt.1)),
389	            });
390	        }
391	    }
392	    // 5. Edges.
393	    let mut edges: Vec<GEdge> = Vec::new();
394	    for e in &sys.edges {
395	        edges.push(GEdge::System(e.src.clone(), e.tgt.clone()));
396	    }
397	    for la in &sys.less_atoms {
398	        edges.push(GEdge::Less(la.clone()));
399	    }
400	    for (g, st) in sys.goals.iter() {
401	        if st.solved { continue; }
402	        if let Goal::Chain(src, tgt) = g {
403	            edges.push(GEdge::UnsolvedChain(src.clone(), tgt.clone()));
404	        }
405	    }
406	    GraphRepr { clusters: Vec::new(), nodes, edges }
407	}
