83	/// A fact / relation atom occupying one premise or conclusion cell, e.g.
84	/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
85	/// for a persistent fact); `args` are its term arguments.
86	#[derive(Clone, Debug)]
87	pub struct Fact {
88	    pub name: String,
89	    pub args: Vec<Term>,
90	}
91	
92	impl Fact {
93	    pub fn new(name: &str, args: Vec<Term>) -> Self {
94	        Fact { name: name.to_string(), args }
95	    }
96	
97	    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
98	    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
99	    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
100	    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
101	    pub fn render_flat(&self) -> String {
102	        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
103	        pad(&self.name, &inner)
104	    }
105	
106	    /// Flat rendering with abbreviations applied to registered sub-terms
107	    /// (`table` maps a term's full rendering to its abbreviation name).
108	    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
109	        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
110	        pad(&self.name, &inner)
111	    }
112	}
113	
114	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
115	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
116	fn pad(name: &str, args: &[String]) -> String {
117	    if args.is_empty() {
118	        format!("{}( )", name)
119	    } else {
120	        format!("{}( {} )", name, args.join(", "))
121	    }
122	}
123	
124	/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
125	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
126	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
127	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
128	    if actions.is_empty() {
129	        format!("#{} : {}", temporal, rule)
130	    } else {
131	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
132	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
133	    }
134	}
135	
136	/// Lay `items` out as a **fill** to a target `width`, starting at column
137	/// `open_col` (the alignment column of the group's first element). Returns the
138	/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
139	///
140	/// Greedy fill: keep appending `sep`-joined items to the current line while it
141	/// fits in `width`; otherwise start a new line. This reproduces the observed
142	/// packing (several short arguments share a line, then a break) **given** the
143	/// width; the width itself is the documented gap.
144	pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
145	    if items.is_empty() {
146	        return vec![String::new()];
147	    }
148	    let mut lines: Vec<String> = Vec::new();
149	    let mut cur = String::new();
150	    let mut col = open_col;
151	    for (i, it) in items.iter().enumerate() {
152	        let piece = if cur.is_empty() {
153	            it.clone()
154	        } else {
155	            format!("{}{}", sep, it)
156	        };
157	        if !cur.is_empty() && col + piece.chars().count() > width {
158	            lines.push(std::mem::take(&mut cur));
159	            col = open_col;
160	            cur.push_str(it);
161	            col += it.chars().count();
162	        } else {
163	            cur.push_str(&piece);
164	            col += piece.chars().count();
165	        }
166	        let _ = i;
167	    }
168	    lines.push(cur);
169	    lines
170	}
171	
172	/// Greedy paragraph fill at the **known** width [`FILL_WIDTH`], reproducing the
173	/// observed record-cell packing: elements are laid left-to-right starting at
174	/// column `open_col`; the separator `sep` (e.g. `", "`) is emitted after each
175	/// element and **stays on the current line**, and the next element starts a new
176	/// line iff it would push past [`FILL_WIDTH`] from that point. This reproduces the
177	/// observed first-line packing exactly (e.g. an `Out( <'a01', … > )` whose tuple
178	/// overflows keeps eleven `'aNN'` elements plus the trailing `", "` on line 0,
179	/// then breaks). Continuation lines carry the [`FILL_WIDTH`]-wide `&nbsp;` indent
180	/// via [`join_wrapped`].
181	///
182	/// KNOWN RESIDUAL (BEHAVIOR.md §3f): tamarin's underlying `fsep`-style combinator
183	/// has a one-element lookahead that lets a *continuation* line hold one more
184	/// element than the first line at the same start column; this greedy pass packs
185	/// the first line exactly but a continuation line one element short of that
186	/// lookahead, and it does not model the closing-delimiter peel (`>`/`)` onto their
187	/// own aligned lines) that appears when the last element fills the line.
188	pub fn paragraph_fill(items: &[String], sep: &str, open_col: usize) -> Vec<String> {
189	    if items.is_empty() {
190	        return vec![String::new()];
191	    }
192	    let sep_w = sep.chars().count();
193	    let mut lines: Vec<String> = Vec::new();
194	    let mut cur = String::new();
195	    let mut col = open_col;
196	    for (i, it) in items.iter().enumerate() {
197	        let w = it.chars().count();
198	        if i == 0 {
199	            cur.push_str(it);
200	            col += w;
201	        } else if col + w <= FILL_WIDTH {
202	            cur.push_str(it);
203	            col += w;
204	        } else {
205	            lines.push(std::mem::take(&mut cur));
206	            col = open_col;
207	            cur.push_str(it);
208	            col += w;
209	        }
210	        if i + 1 < items.len() {
211	            // The separator trails the element it follows and stays on the line;
212	            // the *next* element's fit is tested from past it.
213	            cur.push_str(sep);
214	            col += sep_w;
215	        }
216	    }
217	    lines.push(cur);
218	    lines
219	}
220	
221	/// Join physical `lines` (a FILL of same-aligned elements, e.g. a broken action
222	/// list `[a1, a2]`) into a single record-cell string using the observed wrap
223	/// format: each physical line is followed by `\l`, and every continuation line is
224	/// prefixed by `open_col` `&nbsp;` entities (the verified alignment indent). The
225	/// trailing `\l` after the last line is part of the observed format (graphviz
226	/// left-justification). The caller escapes the line contents first (via
227	/// [`escape_record`]) — `\l` and `&nbsp;` are literal control sequences and must
228	/// not be escaped.
229	///
230	/// This reproduces the fill case where the closing delimiter stays attached to
231	/// the last element (`… )]`). A function/fact whose closing `)` breaks onto its
232	/// *own* line at the functor column is a distinct layout the pretty-printer's
233	/// break decision produces (a documented GAP), not modelled here.
234	pub fn join_wrapped(lines: &[String], open_col: usize) -> String {
235	    let indent = "&nbsp;".repeat(open_col);
236	    let mut out = String::new();
237	    for (i, ln) in lines.iter().enumerate() {
238	        if i > 0 {
239	            out.push_str(&indent);
240	        }
241	        out.push_str(ln);
242	        out.push_str("\\l");
243	    }
244	    out
245	}
246	
247	/// Width of a rendered fragment in the pretty-printer's column model: Unicode
248	/// scalar count (matches the observed column boundary).
249	fn width(s: &str) -> usize {
250	    s.chars().count()
251	}
252	
253	/// One physical line of a wrapped cell: its `&nbsp;` indent column and its
254	/// un-escaped text (escaping is applied when the lines are joined).
255	type PLine = (usize, String);
256	
257	/// One fill element with the separator that precedes it, the indent to use if it
258	/// starts a new line, and whether a break before it is forced (`hard`).
259	struct Unit {
260	    sep: &'static str,
261	    text: String,
262	    indent: usize,
263	    hard: bool,
264	}
265	
266	/// Greedy fill layout (BEHAVIOR.md §3f). Starting from `open_text` at column
267	/// `start_col`, place each unit's separator on the current line and then its text,
268	/// wrapping to the unit's indent when the text would pass [`FILL_WIDTH`] (or on a
269	/// `hard` unit). Returns the physical lines.
270	fn run_layout(open_text: &str, start_col: usize, units: &[Unit]) -> Vec<PLine> {
271	    let mut lines: Vec<PLine> = Vec::new();
272	    let mut cur = open_text.to_string();
273	    let mut col = start_col;
274	    let mut line_indent = 0usize;
275	    for u in units {
276	        cur.push_str(u.sep);
277	        col += width(u.sep);
278	        let w = width(&u.text);
279	        if u.hard || col + w > FILL_WIDTH {
280	            lines.push((line_indent, std::mem::take(&mut cur)));
281	            line_indent = u.indent;
282	            cur.push_str(&u.text);
283	            col = u.indent + w;
284	        } else {
285	            cur.push_str(&u.text);
286	            col += w;
287	        }
288	    }
289	    lines.push((line_indent, cur));
290	    lines
291	}
292	
293	/// Split `s` at top-level occurrences of `", "` — respecting `()`/`<>`/`[]` nesting
294	/// and `'…'` quotes — into the comma-separated elements of a fill group.
295	fn split_top_commas(s: &str) -> Vec<String> {
296	    let chars: Vec<char> = s.chars().collect();
297	    let mut parts: Vec<String> = Vec::new();
298	    let mut cur = String::new();
299	    let mut depth = 0i32;
300	    let mut in_quote = false;
301	    let mut i = 0;
302	    while i < chars.len() {
303	        let c = chars[i];
304	        if in_quote {
305	            cur.push(c);
306	            if c == '\'' {
307	                in_quote = false;
308	            }
309	            i += 1;
310	            continue;
311	        }
312	        match c {
313	            '\'' => {
314	                in_quote = true;
315	                cur.push(c);
316	                i += 1;
317	            }
318	            '(' | '<' | '[' => {
319	                depth += 1;
320	                cur.push(c);
321	                i += 1;
322	            }
323	            ')' | '>' | ']' => {
324	                depth -= 1;
325	                cur.push(c);
326	                i += 1;
327	            }
328	            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
329	                parts.push(std::mem::take(&mut cur));
330	                i += 2;
331	            }
332	            _ => {
333	                cur.push(c);
334	                i += 1;
335	            }
336	        }
337	    }
338	    parts.push(cur);
339	    parts
340	}
341	
342	fn is_tuple(s: &str) -> bool {
343	    s.starts_with('<') && s.ends_with('>')
344	}
345	
346	/// Lay out a tuple `<e1, e2, …>` whose `<` sits at column `base_col`: fill the
347	/// elements (`fillSep`) at `base_col + 1`, and peel the `>` to its own line at
348	/// `base_col` iff it does not fit on the last element's line.
349	fn layout_tuple(inner: &str, base_col: usize) -> Vec<PLine> {
350	    let elems = split_top_commas(inner);
351	    let open_col = base_col + 1;
352	    let mut units: Vec<Unit> = Vec::with_capacity(elems.len() + 1);
353	    for (i, e) in elems.iter().enumerate() {
354	        units.push(Unit { sep: if i == 0 { "" } else { ", " }, text: e.clone(), indent: open_col, hard: false });
355	    }
356	    units.push(Unit { sep: "", text: ">".to_string(), indent: base_col, hard: false });
357	    run_layout("<", open_col, &units)
358	}
359	
360	/// Lay out a fact / relation cell `NAME( a1, a2, … )`. If its flat rendering fits
361	/// [`FILL_WIDTH`] it stays on one line. Otherwise its arguments fill at the
362	/// argument column; a sole tuple argument recurses into [`layout_tuple`]; and the
363	/// closing `)` peels onto its own line at column 0 (the padded ` )` space becomes
364	/// the break).
365	fn layout_fact(flat: &str) -> Vec<PLine> {
366	    if width(flat) <= FILL_WIDTH {
367	        return vec![(0, flat.to_string())];
368	    }
369	    let Some(lp) = flat.find("( ") else {
370	        return vec![(0, flat.to_string())];
371	    };
372	    if !flat.ends_with(" )") {
373	        return vec![(0, flat.to_string())];
374	    }
375	    let open_str = &flat[..lp + 2]; // "NAME( "
376	    let content = &flat[lp + 2..flat.len() - 2];
377	    let open_col = width(open_str);
378	    let args = split_top_commas(content);
379	
380	    // A sole tuple argument: the fact opens "NAME( <" and the tuple fills inside.
381	    if args.len() == 1 && is_tuple(&args[0]) {
382	        let inner = &args[0][1..args[0].len() - 1];
383	        let tlines = layout_tuple(inner, open_col);
384	        let mut lines: Vec<PLine> = Vec::with_capacity(tlines.len() + 2);
385	        lines.push((0, format!("{}{}", open_str, tlines[0].1)));
386	        for t in &tlines[1..] {
387	            lines.push(t.clone());
388	        }
389	        lines.push((0, ")".to_string()));
390	        return lines;
391	    }
392	
393	    // General fill of the (atomic) arguments; the fact's `)` always peels to col 0.
394	    let mut units: Vec<Unit> = Vec::with_capacity(args.len() + 1);
395	    for (i, a) in args.iter().enumerate() {
396	        units.push(Unit { sep: if i == 0 { "" } else { ", " }, text: a.clone(), indent: open_col, hard: false });
397	    }
398	    units.push(Unit { sep: "", text: ")".to_string(), indent: 0, hard: true });
399	    run_layout(open_str, open_col, &units)
400	}
401	
402	/// Lay out an info cell `#t : Rule[a1, a2, …]`. The action list uses a vertical
403	/// `sep` — one action per line when the cell overflows [`FILL_WIDTH`] — with the
404	/// trailing `,` kept on each non-final line and the `]` attached to the last
405	/// action.
406	fn layout_info(flat: &str) -> Vec<PLine> {
407	    if width(flat) <= FILL_WIDTH {
408	        return vec![(0, flat.to_string())];
409	    }
410	    let Some(lb) = flat.find('[') else {
411	        return vec![(0, flat.to_string())];
412	    };
413	    if !flat.ends_with(']') {
414	        return vec![(0, flat.to_string())];
415	    }
416	    let open_str = &flat[..lb + 1]; // "#t : Rule["
417	    let content = &flat[lb + 1..flat.len() - 1];
418	    let open_col = width(open_str);
419	    let acts = split_top_commas(content);
420	    let mut units: Vec<Unit> = Vec::with_capacity(acts.len());
421	    for (i, a) in acts.iter().enumerate() {
422	        // Each action begins its own line (a vertical `sep`, hard break after the
423	        // first); non-final actions carry a trailing `,`, the last carries `]`.
424	        let text = if i + 1 < acts.len() { format!("{},", a) } else { format!("{}]", a) };
425	        units.push(Unit { sep: "", text, indent: open_col, hard: i > 0 });
426	    }
427	    run_layout(open_str, open_col, &units)
428	}
429	
430	/// Render one record cell from its flat (un-escaped) text into the exact label
431	/// bytes: single line (escaped) when it fits [`FILL_WIDTH`], otherwise the wrapped
432	/// form — physical lines each prefixed by their `&nbsp;` indent, escaped, and
433	/// terminated by `\l` (trailing `\l` included), per BEHAVIOR.md §3f.
434	///
435	/// Dispatch by cell shape: an info cell (`#t : Rule[…]`) uses the vertical action
436	/// `sep`; a fact / relation cell (`NAME( … )`) uses the greedy argument/tuple fill
437	/// with the delimiter peel. The same entry serves the Term-based path (feed
438	/// [`Fact::render_flat`]) and the pre-rendered-string path (feed the caller's
439	/// already-rendered cell text): the wrap and escape apply identically.
440	pub fn wrap_cell(flat: &str) -> String {
441	    let lines = if flat.starts_with('#') && flat.contains('[') {
442	        layout_info(flat)
443	    } else {
444	        layout_fact(flat)
445	    };
446	    if lines.len() == 1 && lines[0].0 == 0 {
447	        return escape_record(&lines[0].1);
448	    }
449	    let mut out = String::new();
450	    for (indent, text) in &lines {
451	        out.push_str(&"&nbsp;".repeat(*indent));
452	        out.push_str(&escape_record(text));
453	        out.push_str("\\l");
454	    }
455	    out
456	}
